// Handle both real uploads (via ImgBB) and test data paths
const inputData = $json;

// Check if we're coming from ImgBB (real upload) or Test Data (test path)
let prevData = {};
let imageUrl = '';

// If coming from ImgBB, inputData will have data.image.url
if (inputData.data?.image?.url || inputData.data?.url) {
  // Real path: ImgBB response
  imageUrl = inputData.data?.image?.url || inputData.data?.url || '';

  // Try to get form data from Upload Your Photo node
  try {
    prevData = $('Upload Your Photo').first().json || {};
  } catch (e) {
    prevData = {};
  }
} else if (inputData.user_photo_url) {
  // Test path: already has user_photo_url from Test Data (Edit Fields)
  imageUrl = inputData.user_photo_url;
  prevData = inputData;
} else {
  // Fallback: use whatever data we have
  prevData = inputData;
  imageUrl = inputData.user_photo_url || '';
}

return {
  json: {
    ...prevData,
    user_photo_url: imageUrl,
    imgbb_success: !!imageUrl
  }
};

const config = $('Set Configuration').first().json;
const mode = config.generation_mode || '';
const numScenes = config.num_scenes || 5;
const customScenes = config.custom_scenes || '';
const presetCollection = config.preset_collection || '';
const aiPrompt = config.ai_prompt || '';

const presets = {
  '80s Action Legends': [
    { celebrity: 'Arnold Schwarzenegger as the T-800', movie: 'Terminator 2', costume: 'black leather biker jacket, battle damage showing chrome', location: 'the industrial steel mill with molten sparks', gesture: 'thumbs-up', era: '1991 sci-fi action' },
