// Check PiAPI Kling video status
// States: 'pending', 'processing', 'completed', 'failed'
const videoData = $input.item.json;
const MAX_RETRIES = 120;
const retryCount = videoData.retryCount || 0;

// PiAPI response structure: data.status, data.error, data.output
const taskData = videoData.data || videoData;

// IMPORTANT: Preserve task_id at root level for polling loop
const task_id = videoData.task_id || taskData.task_id || videoData.data?.task_id;

// Check for REAL errors (code !== 0 or non-empty message)
const errorObj = taskData.error || videoData.error;
if (errorObj && (errorObj.code !== 0 || (errorObj.message && errorObj.message.length > 0))) {
  const errorMsg = errorObj.message || errorObj.raw_message || JSON.stringify(errorObj);

  // Check for credit errors
  if (errorMsg.includes('credit') || errorMsg.includes('balance') || errorMsg.includes('insufficient')) {
    return { json: { task_id, skipVideo: true, videoReady: false, reason: 'Insufficient PiAPI credits', hasError: true } };
  }

  return { json: { task_id, skipVideo: true, videoReady: false, reason: errorMsg, hasError: true } };
}

if (retryCount >= MAX_RETRIES) {
  return { json: { task_id, skipVideo: true, videoReady: false, reason: 'Timeout after 120 retries' } };
}

const status = taskData.status;

if (status === 'completed') {
  // PiAPI returns video URL in data.output.works[0].resource.resource or similar
  let videoUrl = null;
  if (taskData.output?.works && taskData.output.works.length > 0) {
    videoUrl = taskData.output.works[0].resource?.resource || taskData.output.works[0].url;
  }
  videoUrl = videoUrl || taskData.output?.video_url || taskData.output?.video || taskData.output?.result?.video_url;

  return { 
    json: { 
      task_id,
      videoReady: true, 
      video_url: videoUrl 
    } 
  };
} else if (status === 'failed') {
  return { json: { task_id, skipVideo: true, videoReady: false, reason: taskData.error?.message || 'Task failed' } };
}

// Still processing (pending, processing)
return { 
  json: { 
    task_id,
    videoReady: false, 
    continuePolling: true, 
    retryCount: retryCount + 1,
    retryDelay: 5
  } 
};

const all = $input.first().json.data || [];
all.sort((a, b) => Number(a.clip_index) - Number(b.clip_index));
return [{ json: { video_urls: all.map(x => x.video_url).filter(Boolean) } }];

const videoUrls = $input.first().json.video_urls || [];
return videoUrls.map((url, index) => ({
  json: {
    video_url: url,
    video_index: index + 1,
    total_videos: videoUrls.length
  }
}));

// Write video binary to disk - workaround for readWriteFile bug
const fs = require('fs');
const path = require('path');

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const videoIndex = item.json.video_index;
  const executionId = $execution.id;
  const fileName = `/tmp/movie_set_clip_${videoIndex}_${executionId}.mp4`;

  // Get binary data
  const binaryData = item.binary?.data;
  if (!binaryData) {
    throw new Error(`No binary data found for item ${i}`);
  }

  // Get the actual buffer from n8n's binary helper
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

  // Write to file
  fs.writeFileSync(fileName, buffer);

  console.log(`Wrote ${buffer.length} bytes to ${fileName}`);

  results.push({
    json: {
      ...item.json,
      file_path: fileName,
      file_size: buffer.length
    }
  });
}

return results;

const items = $input.all();
const paths = items.map(i => i.json.file_path).filter(Boolean);
const failedCount = items.filter(i => !i.json.file_path).length;

// Log failures for observability
if (failedCount > 0) {
  console.log(`⚠️ ${failedCount} video(s) failed to generate`);
}

if (!paths.length || paths.length === 0) {
  throw new Error('All video clips failed to generate. Check PiAPI credits or API status.');
}

// Handle single video - skip FFmpeg stitch
if (paths.length === 1) {
  return [{
    json: {
      skip_stitch: true,
      single_video_path: paths[0],
      stitch_inputs: paths[0],
      stitched_output_path: paths[0],
      had_failures: failedCount > 0,
      clips_generated: 1,
      clips_failed: failedCount
    }
  }];
}

// Multiple videos - proceed with stitch
return [{
  json: {
    skip_stitch: false,
    stitch_inputs: paths.join('\n'),
    stitched_output_path: `/tmp/stitched_${$execution.id}.mp4`,
    had_failures: failedCount > 0,
    clips_generated: paths.length,
    clips_failed: failedCount
  }
}];

// Read the video and return as binary for WhatsApp
const fs = require('fs');
const config = $('Set Configuration').first().json;
const timestamp = Date.now();

const stitchResult = $input.first().json;

// Check if we're in skip_stitch mode (single video)
let skipStitch = stitchResult.skip_stitch || false;
let outputPath;
let videoUrl = null;

if (skipStitch) {
  // Single video mode - get the video URL from aggregate
  try {
    const aggregatedData = $('Aggregate All Videos').first().json;
    if (aggregatedData && aggregatedData.data && aggregatedData.data.length > 0) {
      videoUrl = aggregatedData.data[0].video_url;
      console.log('Got video URL from Aggregate:', videoUrl);
    }
  } catch (e) {
    console.log('Could not get video URL from aggregate:', e.message);
  }

  outputPath = stitchResult.single_video_path;
  console.log('Single video mode - path:', outputPath);

  // If we have a video URL, use URL mode (more reliable for WAHA)
  if (videoUrl) {
    return [{
      json: {
        session_id: `session_${timestamp}`,
        status: 'Your Celebrity Selfie Video is Ready!',
        file_path: outputPath,
        video_url: videoUrl,
        file_size_mb: 0,
        user_name: config.user_name || 'User',
        skip_stitch: true,
        use_url_mode: true,
        created_at: new Date().toISOString()
      }
    }];
  }

  // Fallback: try to get binary from Download Video Binary
  try {
    const downloadedVideo = $('Download Video Binary').first();
    if (downloadedVideo && downloadedVideo.binary && downloadedVideo.binary.data) {
      return [{
        json: {
          session_id: `session_${timestamp}`,
          status: 'Your Celebrity Selfie Video is Ready!',
          file_path: outputPath,
          file_size_mb: downloadedVideo.binary.data.fileSize ? 
            parseFloat((downloadedVideo.binary.data.fileSize / (1024 * 1024)).toFixed(2)) : 0,
          user_name: config.user_name || 'User',
          skip_stitch: true,
          use_url_mode: false,
          created_at: new Date().toISOString()
        },
        binary: downloadedVideo.binary
      }];
    }
  } catch (e) {
    console.log('Could not get binary from Download Video Binary:', e.message);
  }
} else {
  // Normal stitch mode - FFmpeg output
  outputPath = stitchResult.outputPath;

  if (!stitchResult.success || !outputPath) {
    return [{
      json: {
        session_id: `session_${timestamp}`,
        status: 'FFmpeg stitch failed',
        error: stitchResult.stderr || 'Unknown error',
        created_at: new Date().toISOString()
      }
    }];
  }
}

// Check if file exists
if (!fs.existsSync(outputPath)) {
  return [{
    json: {
      session_id: `session_${timestamp}`,
      status: 'Video file not found',
      error: `File not found: ${outputPath}`,
      created_at: new Date().toISOString()
    }
  }];
}

// Read the file and get stats
const stats = fs.statSync(outputPath);
const fileSizeMB = (stats.size / (1024 * 1024)).toFixed(2);
const buffer = fs.readFileSync(outputPath);

// Create binary data using n8n's helper
const binaryData = await this.helpers.prepareBinaryData(buffer, 'celebrity_selfie_movie.mp4', 'video/mp4');

return [{
  json: {
    session_id: `session_${timestamp}`,
    status: skipStitch ? 'Your Celebrity Selfie Video is Ready!' : 'Your Celebrity Selfie Movie is Ready!',
    file_path: outputPath,
    file_size_mb: parseFloat(fileSizeMB),
    user_name: config.user_name || 'User',
    skip_stitch: skipStitch,
    use_url_mode: false,
    created_at: new Date().toISOString()
  },
  binary: {
    data: binaryData
  }
}];

// Handle both real uploads (via ImgBB) and test data paths
const inputData = $json;

