function parseCustomScenes(customText) {
  if (!customText || !customText.trim()) return [];
  const lines = customText.split('\n').filter(line => line.trim() && line.includes('|'));
  return lines.map((line, index) => {
    const parts = line.split('|').map(p => p.trim());
    return {
      scene_id: index + 1,
      celebrity: parts[0] || 'Celebrity',
      movie: parts[1] || 'Movie',
      era: parts[2] || 'Unknown era',
      location: parts[3] || 'iconic movie set',
      costume: parts[4] || 'their iconic costume',
      gesture: parts[5] || 'friendly pose'
    };
  });
}

// Parse AI prompt - improved to handle various formats
function parseAiPrompt(aiPrompt, numScenes) {
  if (!aiPrompt || !aiPrompt.trim()) return null;

  const prompt = aiPrompt.trim();
  const scenes = [];

  // Pattern 1: "1st scene selfie with X, 2nd scene selfie with Y"
  const selfieWithPattern = /(?:(?:\d+(?:st|nd|rd|th)?\s+)?scene\s+)?(?:selfie\s+)?with\s+([^,]+)/gi;
  let selfieMatches = [...prompt.matchAll(selfieWithPattern)];

  if (selfieMatches.length >= 2) {
    for (const match of selfieMatches) {
      const celebrity = match[1].trim();
      if (celebrity && celebrity.length > 2) {
        scenes.push(createSceneFromCelebrity(celebrity, scenes.length + 1));
      }
    }
    if (scenes.length >= 2) return scenes.slice(0, numScenes);
  }

  // Pattern 2: Numbered list "1. X 2. Y 3. Z"
  const numberedPattern = /(?:(?:Scene\s*)?(\d+)[.:\)]\s*)([^\d][^.]*?)(?=(?:(?:Scene\s*)?\d+[.:\)])|$)/gi;
  let matches = [...prompt.matchAll(numberedPattern)];

  if (matches.length >= 2) {
    for (const match of matches) {
      const sceneText = match[2].trim();
      if (sceneText) {
        const scene = parseSceneDescription(sceneText, scenes.length + 1);
        scenes.push(scene);
      }
    }
    if (scenes.length >= 2) return scenes.slice(0, numScenes);
  }

  // Pattern 3: Comma-separated list "X, Y, Z"
  const parts = prompt.split(/,/).map(p => p.trim()).filter(p => p.length > 2);
  if (parts.length >= 2) {
    for (const part of parts) {
      // Remove ordinal prefixes like "1st", "2nd", "scene", "selfie with"
      let cleanPart = part
        .replace(/^\d+(?:st|nd|rd|th)?\s*/i, '')
        .replace(/^scene\s*/i, '')
        .replace(/^selfie\s+with\s*/i, '')
        .trim();

      if (cleanPart && cleanPart.length > 2) {
        scenes.push(createSceneFromCelebrity(cleanPart, scenes.length + 1));
      }
    }
    if (scenes.length >= 2) return scenes.slice(0, numScenes);
  }

  return null;
}

// Create a scene object from just a celebrity name
function createSceneFromCelebrity(celebrityName, sceneId) {
  // Clean up the celebrity name
  const name = celebrityName
    .replace(/^(?:with|and|,)\s*/i, '')
    .replace(/\s+(?:at|in|from)\s+.*/i, '') // Remove location info
    .trim();

  // Determine context based on celebrity
  let movie = 'iconic performance';
  let era = 'their prime';
  let location = 'concert stage';
  let costume = 'their signature outfit';
  let gesture = 'friendly pose';

  const nameLower = name.toLowerCase();

  // Opera/Classical
  if (nameLower.includes('pavarotti') || nameLower.includes('bocelli') || nameLower.includes('domingo')) {
    movie = 'legendary opera performance';
    location = 'grand opera house with ornate decorations';
    costume = 'elegant tuxedo';
    gesture = 'operatic gesture';
    era = 'peak of career';
  }
  // Action stars
  else if (nameLower.includes('stallone') || nameLower.includes('sylvester')) {
    movie = 'Rocky';
    location = 'boxing gym with punching bags';
    costume = 'boxing robe and gloves';
    gesture = 'fist raised';
    era = '1980s action star';
  }
  else if (nameLower.includes('schwarzenegger') || nameLower.includes('arnold')) {
    movie = 'Terminator';
    location = 'futuristic set with metal structures';
    costume = 'leather jacket and sunglasses';
    gesture = 'thumbs up';
    era = '1980s action star';
  }
  // Political figures
  else if (nameLower.includes('rabin') || nameLower.includes('itzhak')) {
    movie = 'historic peace ceremony';
    location = 'White House lawn';
    costume = 'formal suit and tie';
    gesture = 'handshake pose';
    era = '1990s';
  }
  // Default for other celebrities
  else {
    movie = 'their most famous moment';
    location = 'red carpet event';
    costume = 'elegant formal attire';
    gesture = 'warm smile';
  }

  return {
    scene_id: sceneId,
    celebrity: name,
    movie: movie,
    era: era,
    location: location,
    costume: costume,
    gesture: gesture
  };
}

function parseSceneDescription(text, sceneId) {
  const lowerText = text.toLowerCase();

  // Extract celebrity name
  let celebrity = text;
  const celebPatterns = [
    /^([^,]+?)(?:\s+(?:celebrating|giving|scoring|at|in|wearing|standing))/i,
    /^([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)/
  ];
  for (const pattern of celebPatterns) {
    const match = text.match(pattern);
    if (match) {
      celebrity = match[1].trim();
      break;
    }
  }

  return createSceneFromCelebrity(celebrity, sceneId);
}

let scenes = [];

if (mode.includes('Custom')) {
  scenes = parseCustomScenes(customScenes);
} else if (mode.includes('Presets')) {
  for (const [key, value] of Object.entries(presets)) {
    if (presetCollection.includes(key) || key.includes(presetCollection.split('(')[0].trim())) {
      scenes = value.map((s, i) => ({ ...s, scene_id: i + 1 }));
      break;
    }
  }
  if (scenes.length === 0) {
    scenes = presets['80s Action Legends'].map((s, i) => ({ ...s, scene_id: i + 1 }));
  }
} else {
  // AI Mode - Parse the prompt
  const parsedScenes = parseAiPrompt(aiPrompt, numScenes);

  if (parsedScenes && parsedScenes.length > 0) {
    scenes = parsedScenes;
  } else {
    // Fallback to keyword matching for presets
    const prompt = aiPrompt.toLowerCase();
    if (prompt.includes('80s') || prompt.includes('action')) {
      scenes = presets['80s Action Legends'];
    } else if (prompt.includes('marvel') || prompt.includes('superhero')) {
      scenes = presets['Marvel Cinematic Universe Heroes'];
    } else if (prompt.includes('star wars') || prompt.includes('jedi')) {
      scenes = presets['Star Wars Saga Characters'];
    } else {
      scenes = presets['90s Blockbusters'];
    }
    scenes = scenes.map((s, i) => ({ ...s, scene_id: i + 1 }));
  }
}

scenes = scenes.slice(0, numScenes).map((s, i) => ({ ...s, scene_id: i + 1 }));

return scenes.map(scene => ({ json: scene }));

