// Check PiAPI Kling video status
// States: 'pending', 'processing', 'completed', 'failed'
const videoData = $input.item.json;
const MAX_RETRIES = 120;
const retryCount = videoData.retryCount || 0;

// PiAPI response structure: data.status, data.error, data.output
const taskData = videoData.data || videoData;

// IMPORTANT: Preserve task_id at root level for polling loop
const task_id = videoData.task_id || taskData.task_id || videoData.data?.task_id;

// Check for REAL errors (code !== 0 or non-empty message)
const errorObj = taskData.error || videoData.error;
if (errorObj && (errorObj.code !== 0 || (errorObj.message && errorObj.message.length > 0))) {
  const errorMsg = errorObj.message || errorObj.raw_message || JSON.stringify(errorObj);

  // Check for credit errors
  if (errorMsg.includes('credit') || errorMsg.includes('balance') || errorMsg.includes('insufficient')) {
    return { json: { task_id, skipVideo: true, videoReady: false, reason: 'Insufficient PiAPI credits', hasError: true } };
  }

  return { json: { task_id, skipVideo: true, videoReady: false, reason: errorMsg, hasError: true } };
}

if (retryCount >= MAX_RETRIES) {
  return { json: { task_id, skipVideo: true, videoReady: false, reason: 'Timeout after 120 retries' } };
}

const status = taskData.status;

if (status === 'completed') {
  // PiAPI returns video URL in data.output.works[0].resource.resource or similar
  let videoUrl = null;
  if (taskData.output?.works && taskData.output.works.length > 0) {
    videoUrl = taskData.output.works[0].resource?.resource || taskData.output.works[0].url;
  }
  videoUrl = videoUrl || taskData.output?.video_url || taskData.output?.video || taskData.output?.result?.video_url;

  return { 
    json: { 
      task_id,
      videoReady: true, 
      video_url: videoUrl 
    } 
  };
} else if (status === 'failed') {
  return { json: { task_id, skipVideo: true, videoReady: false, reason: taskData.error?.message || 'Task failed' } };
}

// Still processing (pending, processing)
return { 
  json: { 
    task_id,
    videoReady: false, 
    continuePolling: true, 
    retryCount: retryCount + 1,
    retryDelay: 5
  } 
};

const all = $input.first().json.data || [];
all.sort((a, b) => Number(a.clip_index) - Number(b.clip_index));
return [{ json: { video_urls: all.map(x => x.video_url).filter(Boolean) } }];

